'use client';

import { useState, useCallback, useRef, useEffect } from 'react';

export interface Message {
  id: string;
  type: 'user' | 'bot';
  content: string;
  timestamp: Date;
}

export function useChat() {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      type: 'bot',
      content: `Hi! I'm a chatbot about Tulasi Priya's profile. Feel free to ask me about skills, experience, projects, or how to get in touch!`,
      timestamp: new Date(),
    },
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  const addMessage = useCallback(
    (type: 'user' | 'bot', content: string) => {
      const newMessage: Message = {
        id: Date.now().toString(),
        type,
        content,
        timestamp: new Date(),
      };
      setMessages((prev) => [...prev, newMessage]);
      return newMessage;
    },
    []
  );

  const sendMessage = useCallback(
    async (userMessage: string) => {
      if (!userMessage.trim()) return;

      // Add user message
      addMessage('user', userMessage);
      setInput('');
      setIsLoading(true);

      // Simulate bot response delay
      await new Promise((resolve) => setTimeout(resolve, 300));

      // Get bot response
      try {
        const { findBestMatch } = await import('@/data/chatbot-qa');
        const match = findBestMatch(userMessage);
        const botResponse =
          match?.answer ||
          `I'm not sure how to answer that. Try asking me about my skills, experience, projects, or how to contact me!`;
        addMessage('bot', botResponse);
      } catch (error) {
        addMessage('bot', 'Sorry, something went wrong. Please try again.');
      }

      setIsLoading(false);
    },
    [addMessage]
  );

  return {
    messages,
    input,
    setInput,
    isLoading,
    sendMessage,
    messagesEndRef,
  };
}
